function safeBatchTransferFrom(address from, address to, uint256[] calldata ids, uint256[] calldata amounts, bytes calldata data) public virtual {
    require(ids.length == amounts.length, 'ArrayLengthsMismatch');
    require(to != address(0), 'TransferToZeroAddress');
    require(from == msg.sender || isApprovedForAll[from][msg.sender], 'NotOwnerNorApproved');
    for (uint256 i = 0; i < ids.length; i++) {
        uint256 id = ids[i];
        uint256 amount = amounts[i];
        uint256 fromBalance = _balanceOf[from][id];
        require(fromBalance >= amount, 'InsufficientBalance');
        _balanceOf[from][id] = fromBalance - amount;
        _balanceOf[to][id] += amount;
    }
    emit TransferBatch(msg.sender, from, to, ids, amounts);
    _doSafeBatchTransferAcceptanceCheck(msg.sender, from, to, ids, amounts, data);
}

